#include<iostream>#include<vector>#include<cmath>#include<algorithm>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<ll>a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        ll g1=0;        ll g2= 0;        for(int i=0;i<n;i++){            if(i%2==0){                g1=__gcd(a[i],g1);            }            else{                g2= __gcd(a[i],g2);            }        }        bool possible_g2= true;        for(int i=0;i<n;i+=2){                 if(a[i]%g2==0){                    possible_g2= false;                    break;                }        }        bool possible_g1= true;        for(int i=1;i<n;i+=2){                 if(a[i]%g1==0){                    possible_g1= false;                    break;                }        }        if(possible_g1)cout<<g1<<"\n";        else if(possible_g2)cout<<g2<<"\n";        else cout<<0<<"\n";    }}